import os
import sys
import shutil
import builtins
import tempfile

# --- Variables & Paths ---
BASE_DIR = os.path.dirname(os.path.abspath(sys.executable))
os.environ['TCL_LIBRARY'] = r"C:\GhostPython\tcl\tcl8.6.9"
os.environ['TK_LIBRARY'] = r"C:\GhostPython\tcl\tk8.6.9"
CONFIG_PATH = os.path.join(BASE_DIR, "settings.config")
sys.ps1 = "Ghost@Python> "

COLORS = {
    "green": "\033[92m",
    "yellow": "\033[93m",
    "red": "\033[91m",
    "reset": "\033[0m"
}

# --- Custom Command Functions ---
def clean():
    """Remove all __pycache__ directories recursively from current working directory."""
    count = 0
    try:
        for root, dirs, _ in os.walk(os.getcwd()):
            if "__pycache__" in dirs:
                cache_path = os.path.join(root, "__pycache__")
                try:
                    shutil.rmtree(cache_path)
                    count += 1
                except (OSError, PermissionError) as e:
                    print(f"Ghost: Failed to remove {cache_path}: {e}")
    except Exception as e:
        print(f"Ghost: Error during cleanup: {e}")
    message = f"Successfully cleaned {count} cache folders." if count > 0 else "No cache found."
    print(f"Ghost: {message}")

def tree(path='.', indent=''):
    """
    Display directory structure as a tree, excluding common ignored folders.
    :param path: Root directory to start from
    :param indent: Indentation string for recursive levels
    """
    if path == '.':
        print(f"Ghost Directory Structure of: {os.path.abspath(os.getcwd())}")
    
    try:
        items = sorted(item for item in os.listdir(path) if not item.startswith('.'))
    except PermissionError:
        return
    except (OSError, FileNotFoundError) as e:
        print(f"Ghost: Cannot access '{path}': {e}")
        return

    # Filter out unwanted directories
    filtered = [i for i in items if i not in ['__pycache__', '.git', '.python_history']]
    for i, name in enumerate(filtered):
        is_last = (i == len(filtered) - 1)
        connector = '└── ' if is_last else '├── '
        print(f"{indent}{connector}{name}")
        full_path = os.path.join(path, name)
        if os.path.isdir(full_path):
            extension = '    ' if is_last else '│   '
            tree(full_path, indent + extension)

def libs():
    """Print all Python search paths."""
    print("Ghost Search Paths:")
    for i, path in enumerate(sys.path):
        print(f"  {i}: {path}")

def clear():
    """Clear the terminal screen."""
    os.system('cls' if os.name == 'nt' else 'clear')

# --- Command Registration ---
builtins.tree = tree
builtins.clean = clean
builtins.clear = clear
builtins.libs = libs

# --- Execution Logic ---
if os.path.exists(CONFIG_PATH):
    try:
        with open(CONFIG_PATH, 'r', encoding='utf-8') as f:
            config = {}
            for line in f:
                line = line.strip()
                if '=' in line and not line.startswith('#'):
                    try:
                        key, value = line.split('=', 1)
                        config[key.strip()] = value.strip()
                    except ValueError:
                        continue  # Skip malformed lines
    except (IOError, OSError) as e:
        print(f"DEBUG: Failed to read config file: {e}")
        config = {}

    # Update sys.path based on config
    for folder in ["Lib", "DLLs", "tcl"]:
        path = os.path.join(BASE_DIR, folder)
        if config.get(folder) == "enabled" and os.path.exists(path) and path not in sys.path:
            try:
                sys.path.append(path)
            except Exception as e:
                print(f"Ghost: Failed to add {path} to sys.path: {e}")

    # Detect execution context
    is_interactive = sys.stdin.isatty()
    script_name = sys.argv[0].lower()
    is_installer = any(
        tool in script_name 
        for tool in ['pip', 'setuptools', 'distutils', 'pytest', 'wheel', 'twine']
    )

    # Show banner only in interactive mode, not during automated runs
    if config.get("Title") == "enabled" and is_interactive and not is_installer:
        print(f"{COLORS['yellow']}Ghost Python👻: Active and Initialized.{COLORS['reset']}")
        print(f"{COLORS['green']}Follow me on https://github.com/DAPOWER99{COLORS['reset']}")
        print(f"{COLORS['red']}- Never Edit The BareBones settings.config without knowledge!{COLORS['reset']}")
else:
    print("DEBUG: settings.config file not found!")